            plus_count += rav
            minus_count += rav
            k = max(plus_count, minus_count)
            C = math.factorial(unknown) / (
                math.factorial(unknown - k) * math.factorial(k)
            )
            O = 2**unknown
            res = C / O
            print(f"{res:.12f}")
        else:
            print("0.000000000000")
else:
    print("0.000000000000")

