def main(a, b, l, r):
    period = 2 * a + 2 * b
    qL = (l - 1) // period
    rL = (l - 1) % period + 1
    qR = (r - 1) // period
    rR = (r - 1) % period + 1
    if qL == qR:
        if a < rL <= a + b and a < rR <= a + b:
            return 1
        if 2 * a + b < rL and 2 * a + b < rR:
            return 1
        if 1 <= rL <= a and 1 <= rR <= a:
            return rR - rL + 1
        if a + b < rL <= 2 * a + b and a + b < rR <= 2 * a + b:
            return rR - rL + 1
        if 1 <= rL <= a + b and 1 <= rR <= a + b:
            return a - rL + 1
        if a + b < rL and a + b < rR:
            return (2 * a + b) - rL + 1
