                    count_less += get_combination(i, k)
                    if count_less > n:
                        break
                print(mid, i, j, "c1")
                count_equal += get_combination(i, j)
        print(mid, "is", count_less, count_equal)
        if n < count_less:
            high = mid - 1
        elif count_less + count_equal < n:
            low = mid + 1
        else:
            low_cost = 0
            for i in range(mid // a + 1):
