    return p * (3 * p + 2)


def bin_search(n):
    left = 0
    right = ceil(sqrt(n))
    while right - left > 1:
        mid = (left + right) // 2
        if count(mid) > n:
            right = mid - 1
        else:
            left = mid
    if count(right) > n:
        return left
    else:
        return right


