def gcd(a, b):
    if b == 0:
        return a
    return gcd(b, a % b)


def ksm(a, b, p=int(1e9 + 7)):
    a = a % p
    ans = 1
    while b > 0:
        if b & 1:
            ans = ans * a % p
        b = b >> 1
        a = a * a % p
    return ans


def get_ck(m, n):
    ans = 0

    def get_fac():
        for i in range(2, 100011):
            if pm[i] == 0:
                prime[i][i] = 1
                for j in range(2, 100001 // i + 1):
                    pm[i * j] = 1
                    prime[i * j][i] = 1

